using System;
using System.Threading.Tasks;
using System.Runtime.InteropServices.JavaScript;

namespace ThreeDEngine.Avalonia.WebGL.Interop;

internal static partial class WebGlInterop
{
    private const string EmbeddedModuleBase64 = "";
    private static bool _imported;
    private static Task? _importTask;

    public static async Task EnsureImportedAsync()
    {
        if (_imported)
        {
            return;
        }

        if (_importTask is null)
        {
            _importTask = ImportCoreAsync();
        }

        await _importTask.ConfigureAwait(false);
    }

    private static async Task ImportCoreAsync()
    {
        Exception? last = null;

        try
        {
            var dataUrl = "data:text/javascript;base64," + EmbeddedModuleBase64;
            await JSHost.ImportAsync("ThreeDEngineSceneKit", dataUrl).ConfigureAwait(false);
            _imported = true;
            return;
        }
        catch (Exception ex)
        {
            last = ex;
        }

        foreach (var path in new[]
                 {
                     "/3DEngine/mini3d.webgl.js",
                     "./3DEngine/mini3d.webgl.js",
                     "3DEngine/mini3d.webgl.js"
                 })
        {
            try
            {
                await JSHost.ImportAsync("ThreeDEngineSceneKit", path).ConfigureAwait(false);
                _imported = true;
                return;
            }
            catch (Exception ex)
            {
                last = ex;
            }
        }

        throw last ?? new InvalidOperationException("Unable to import 3DEngine WebGL module.");
    }

    [JSImport("createHost", "ThreeDEngineSceneKit")]
    internal static partial int CreateHost();

    [JSImport("destroyHost", "ThreeDEngineSceneKit")]
    internal static partial void DestroyHost(int hostId);

    [JSImport("updateHost", "ThreeDEngineSceneKit")]
    internal static partial void UpdateHost(int hostId, double x, double y, double width, double height, bool visible);

    [JSImport("renderScene", "ThreeDEngineSceneKit")]
    internal static partial void RenderScene(int hostId, string packetJson);

    [JSImport("updateMetrics", "ThreeDEngineSceneKit")]
    internal static partial void UpdateMetrics(int hostId, string text, bool visible);

    [JSImport("updateCenterCursor", "ThreeDEngineSceneKit")]
    internal static partial void UpdateCenterCursor(int hostId, bool visible);

    [JSImport("requestPointerLock", "ThreeDEngineSceneKit")]
    internal static partial void RequestPointerLock(int hostId);

    [JSImport("exitPointerLock", "ThreeDEngineSceneKit")]
