    [JSImport("uploadRetainedBatchState", "ThreeDEngineSceneKit")]
    internal static partial void UploadRetainedBatchState(int hostId, string batchId, bool usePalette, int paletteWidth, int paletteHeight, string stateFloatsBase64, string paletteRgbaBase64);

    [JSImport("uploadRetainedBatchStateRange", "ThreeDEngineSceneKit")]
